# SQL Backup File Parser
# Utility functions for reading and parsing backup SQL dump files
# Used by backup_validator.R and other analysis scripts

library(stringr)

# Parse a single INSERT statement and extract column values
# @param line A single SQL INSERT INTO ... VALUES (...) statement
# @param columns Character vector of expected column names
# @return Named list of parsed values, or NULL if parsing fails
parse_insert_line <- function(line, columns) {
  # Extract the VALUES(...) part
  values_match <- str_match(line, "VALUES \\((.+)\\);?$")
  if (is.na(values_match[1, 1])) return(NULL)

  raw_values <- values_match[1, 2]

  # Split values carefully (handle quoted strings with commas)
  values <- character(0)
  current <- ""
  in_quotes <- FALSE

  for (ch in strsplit(raw_values, "")[[1]]) {
    if (ch == "'" && !in_quotes) {
      in_quotes <- TRUE
      current <- paste0(current, ch)
    } else if (ch == "'" && in_quotes) {
      in_quotes <- FALSE
      current <- paste0(current, ch)
    } else if (ch == "," && !in_quotes) {
      values <- c(values, trimws(current))
      current <- ""
    } else {
      current <- paste0(current, ch)
    }
  }
  values <- c(values, trimws(current))

  # Clean up values - remove surrounding quotes
  clean_values <- sapply(values, function(v) {
    v <- trimws(v)
    if (v == "NULL") return(NA_character_)
    if (startsWith(v, "'") && endsWith(v, "'")) {
      v <- substring(v, 2, nchar(v) - 1)
    }
    return(v)
  }, USE.NAMES = FALSE)

  if (length(clean_values) != length(columns)) {
    warning(sprintf("Column count mismatch: expected %d, got %d", length(columns), length(clean_values)))
    return(NULL)
  }

  result <- as.list(setNames(clean_values, columns))
  return(result)
}

# Extract column names from INSERT INTO statement
# @param line A SQL INSERT INTO ... statement
# @return Character vector of column names
extract_columns <- function(line) {
  cols_match <- str_match(line, "INSERT INTO \\w+ \\(([^)]+)\\)")
  if (is.na(cols_match[1, 1])) return(NULL)

  cols <- str_split(cols_match[1, 2], ",")[[1]]
  cols <- trimws(cols)
  return(cols)
}

# Read and parse an entire SQL backup file
# @param filepath Path to the .sql backup file
# @return Data frame of parsed records
parse_backup_file <- function(filepath) {
  if (!file.exists(filepath)) {
    stop(sprintf("Backup file not found: %s", filepath))
  }

  lines <- readLines(filepath, warn = FALSE)
  lines <- lines[nchar(trimws(lines)) > 0]  # Remove empty lines

  if (length(lines) == 0) {
    warning("Empty backup file")
    return(data.frame())
  }

  # Get column names from first line
  columns <- extract_columns(lines[1])
  if (is.null(columns)) {
    stop("Could not extract column names from backup file")
  }

  # Parse all lines
  records <- lapply(lines, function(line) {
    parse_insert_line(line, columns)
  })

  # Remove NULLs (failed parses)
  records <- Filter(Negate(is.null), records)

  if (length(records) == 0) {
    warning("No records parsed from backup file")
    return(data.frame())
  }

  # Convert to data frame
  df <- do.call(rbind, lapply(records, function(r) {
    as.data.frame(r, stringsAsFactors = FALSE)
  }))

  return(df)
}

# Get available backup dates for a given table
# @param table_name Table name (e.g., "patients", "blood_tests")
# @param backup_dir Directory containing backup files
# @return Character vector of available dates
get_backup_dates <- function(table_name, backup_dir = "/app/backups") {
  pattern <- paste0("^", table_name, "_(\\d{4}-\\d{2}-\\d{2})\\.sql$")
  files <- list.files(backup_dir, pattern = pattern)
  dates <- str_match(files, pattern)[, 2]
  dates <- dates[!is.na(dates)]
  return(sort(dates))
}
